#include <stdio.h>
#include <graphics.h>

void midpointEllipse(int rx, int ry, int xc, int yc) {
    int x = 0, y = ry;
    // Region 1 initial decision parameter
    int p1 = ry*ry - rx*rx*ry + rx*rx/4;

    while (2*ry*ry*x < 2*rx*rx*y - rx*rx) {
        // Plot 4-way symmetry points
        putpixel(xc+x, yc+y, WHITE);
        putpixel(xc-x, yc+y, WHITE);
        putpixel(xc+x, yc-y, WHITE);
        putpixel(xc-x, yc-y, WHITE);

        x++;
        if (p1 < 0)
            p1 += 2*ry*ry*x + ry*ry;
        else {
            y--;
            p1 += 2*ry*ry*x - 2*rx*rx*y + ry*ry;
        }
    }

    // Region 2 initial decision parameter
    int p2 = ry*ry*(x+0.5)*(x+0.5) + rx*rx*(y-1)*(y-1) - rx*rx*ry*ry;

    while (y >= 0) {
        putpixel(xc+x, yc+y, WHITE);
        putpixel(xc-x, yc+y, WHITE);
        putpixel(xc+x, yc-y, WHITE);
        putpixel(xc-x, yc-y, WHITE);

        y--;
        if (p2 > 0)
            p2 -= 2*rx*rx*y + rx*rx;
        else {
            x++;
            p2 += 2*ry*ry*x - 2*rx*rx*y + rx*rx;
        }
    }
}

int main() {
    int gd = DETECT, gm;
    initgraph(&gd, &gm, "");
    midpointEllipse(100, 60, 200, 150);
    getch();
    closegraph();
    return 0;
}

import java.applet.Applet;
import java.awt.*;

public class BresenhamCircle extends Applet {
    public void drawCircle(int xc, int yc, int r) {
        int x = 0, y = r;
        int d = 3 - 2 * r;  // Initial decision parameter

        while (x <= y) {
            // Plot 8-way symmetry points
            plotCirclePoints(xc, yc, x, y);

            x++;
            if (d < 0) {
                d = d + 4 * x + 6;
            } else {
                y = y - 1;
                d = d + 4 * (x - y) + 10;
            }
        }
    }

    private void plotCirclePoints(int xc, int yc, int x, int y) {
        // 8-way symmetry
        setPixel(xc + x, yc + y);
        setPixel(xc - x, yc + y);
        setPixel(xc + x, yc - y);
        setPixel(xc - x, yc - y);
        setPixel(xc + y, yc + x);
        setPixel(xc - y, yc + x);
        setPixel(xc + y, yc - x);
        setPixel(xc - y, yc - x);
    }

    private void setPixel(int x, int y) {
        // Draw pixel at (x, y)
    }

    public void paint(Graphics g) {
        drawCircle(200, 200, 80);
    }
}
